firmware_template.source:
#include "bme280.h"
#include <Wire.h>
static Adafruit_BME280 bme;
static float _t=0,_h=0,_p=0,_a=0;
static unsigned long _last=0;
void bme280_setup(){Wire.begin();if(!bme.begin(0x76)){Serial.println("[bme280] Fail!");return;}Serial.println("[bme280] OK");}
void bme280_loop(){if(millis()-_last<2000)return;_last=millis();_t=bme.readTemperature();_h=bme.readHumidity();_p=bme.readPressure()/100.0F;_a=bme.readAltitude(1013.25);}
float bme280_get_temperature(){return _t;}
float bme280_get_humidity(){return _h;}
float bme280_get_pressure(){return _p;}
float bme280_get_altitude(){return _a;}
